// Task 4.2: spatially navigate buttons in the given arrow direction
// Extended (calculator-focus-extensions 1.1–1.2): include display as a candidate
function navigateButtons(direction) {
  const active = document.activeElement;
  const activeRect = active.getBoundingClientRect();
  const cx = (activeRect.left + activeRect.right) / 2;
  const cy = (activeRect.top + activeRect.bottom) / 2;

  // Build { el, rect } candidates from all focusable buttons plus the display input
  const focusableEls = getFocusableButtons().concat([display]);
  const candidates = focusableEls
    .filter(function(el) { return el !== active; })
    .map(function(el) { return { el: el, rect: el.getBoundingClientRect() }; })
    .filter(function(c) {
      const bx = (c.rect.left + c.rect.right) / 2;
      const by = (c.rect.top + c.rect.bottom) / 2;
      if (direction === 'ArrowRight') return bx > cx;
      if (direction === 'ArrowLeft')  return bx < cx;
      if (direction === 'ArrowDown')  return by > cy;
      if (direction === 'ArrowUp')    return by < cy;
      return false;
    });

  if (candidates.length === 0) return;

  let best = null;
  let bestDist = Infinity;
  candidates.forEach(function(c) {
    const bx = (c.rect.left + c.rect.right) / 2;
    const by = (c.rect.top + c.rect.bottom) / 2;
    const dist = Math.sqrt((bx - cx) * (bx - cx) + (by - cy) * (by - cy));
    if (dist < bestDist) {
      bestDist = dist;
      best = c;
    }
  });

  // Works for both <button> and <input> without special-casing (1.2)
  if (best) best.el.focus();
}

